#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long ans;
        if(N==1) ans=1;
        else if(N%2==0) ans=N/2+1;
        else ans=(N-1)/2;
        printf("%lld\n", ans);
    }
    return 0;
}

