#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        n = int(data[i])
        if n == 1:
            ans = 1
        elif n % 2 == 0:
            ans = n // 2 + 1
        else:
            ans = (n - 1) // 2
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

